# codeql database create spring-db --language=java --source-root=/path/to/spring
# codeql query run --database=spring-db spring4shell.ql

假设我们有一个简化的C语言HTTP/2服务器，其中处理RST_STREAM帧时存在整数溢出（如流计数器下溢）。我们可以用angr符号化帧内容，并探索到触发溢出的路径。以下是一个示例程序`http2_server.c`：

c
#include <stdint.h>
#include <stdio.h>
#include <stdlib.h>

uint32_t active_streams = 0;

void process_rst_stream(uint32_t stream_id) {
    // 漏洞：无符号整数下溢
    active_streams--;
    if (active_streams > 1000) {
        // 触发异常
        abort();
    }
}

int main(int argc, char *argv[]) {
    if (argc < 2) return 1;
    uint32_t input = atoi(argv[1]);
    process_rst_stream(input);
    return 0;
}

使用angr分析：

python
import angr
import claripy

proj = angr.Project("./http2_server", auto_load_libs=False)

# 符号化命令行参数
arg1 = claripy.BVS("arg1", 32)  # 32位整数
# 创建初始状态，将符号值放入argv[1]
state = proj.factory.entry_state(args=["./http2_server", arg1])

# 定义目标：到达abort()的地址（通过objdump获取）
abort_addr = 0x400567  # 假设
sm = proj.factory.simulation_manager(state)
sm.explore(find=abort_addr)

if sm.found:
    found = sm.found[0]
    solution = found.solver.eval(arg1)
    print(f"Trigger input: {solution}")
    # 输出应为0，因为active_streams初始为0，减1后变为0xFFFFFFFF，大于1000
else:
    print("No path found")

angr会求解出`arg1`的值，使得`active_streams--`后下溢。注意：`active_streams`初始为0，任何输入都会导致下溢，但angr会找到路径。实际中，漏洞需要多次调用，我们可以模拟循环：

c
for (int i = 0; i < 10; i++) {
    process_rst_stream(input);
}

此时，angr需要处理循环，可能路径爆炸。可以使用循环展开或符号化循环次数。更复杂的场景：符号化整个HTTP/2帧结构。

python
# 符号化帧头
frame_type = claripy.BVS("type", 8)
frame_flags = claripy.BVS("flags", 8)
stream_id = claripy.BVS("stream_id", 32)
# 将符号数据写入内存
state.memory.store(0x600000, frame_type)
state.memory.store(0x600001, frame_flags)
state.memory.store(0x600002, stream_id)
# 设置寄存器指向该缓冲区
state.regs.rdi = 0x600000

